// Handle HTTP Request response: { results: [...blocks...] }
// The raw Notion API returns blocks in a results array
const responseData = $input.first().json;
const blocks = responseData.results || [];

const lines = [];

for (const block of blocks) {
  const type = block.type;

  // Direct content field (simplified output from native Notion node)
  if (block.content && typeof block.content === 'string') {
    lines.push(block.content);
    continue;
  }

  // Handle different block types (raw Notion API format)
  switch (type) {
    case 'paragraph':
    case 'bulleted_list_item':
    case 'numbered_list_item':
    case 'quote':
    case 'callout':
      if (block[type]?.rich_text) {
        const text = block[type].rich_text.map(rt => rt.plain_text).join('');
        if (text) {
          const prefix = type === 'bulleted_list_item' ? '• ' :
                        type === 'numbered_list_item' ? '- ' :
                        type === 'quote' ? '> ' : '';
          lines.push(prefix + text);
        }
      }
      break;

    case 'heading_1':
    case 'heading_2':
    case 'heading_3':
      if (block[type]?.rich_text) {
        const text = block[type].rich_text.map(rt => rt.plain_text).join('');
        const hashes = type === 'heading_1' ? '# ' : type === 'heading_2' ? '## ' : '### ';
        if (text) lines.push(hashes + text);
      }
      break;

    case 'table_row':
      if (block.table_row?.cells) {
        const rowText = block.table_row.cells
          .map(cell => Array.isArray(cell) ? cell.map(c => c.plain_text || '').join('') : '')
          .join(' | ');
        if (rowText.trim()) lines.push('| ' + rowText + ' |');
      }
      break;

    case 'divider':
      lines.push('---');
      break;

    case 'code':
      if (block.code?.rich_text) {
        const code = block.code.rich_text.map(rt => rt.plain_text).join('');
        lines.push('```\n' + code + '\n```');
      }
      break;

    case 'to_do':
      if (block.to_do?.rich_text) {
        const text = block.to_do.rich_text.map(rt => rt.plain_text).join('');
        const checked = block.to_do.checked ? '[x]' : '[ ]';
        if (text) lines.push(`- ${checked} ${text}`);
      }
      break;
  }
}

const illustrationGuide = lines
  .filter(line => line && line.trim().length > 0)
  .join('\n');

return [{ json: { illustrationGuide } }];

